  "audioData": {{ JSON.stringify($json.data) }}
}

parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "array",
  "items": {
    "type": "object",
    "required": ["categoryID", "categoryName", "reason", "score"],
    "properties": {
      "categoryID": {
        "type": "string",
        "description": "Unique identifier for the evaluation category"
      },
      "categoryName": {
        "type": "string",
        "description": "Human-readable name of the evaluation category"
      },
      "reason": {
        "type": "string",
        "description": "Concise explanation of the score, max 3 sentences"
      },
      "score": {
        "type": "integer",
        "minimum": 0,
        "maximum": 10,
        "description": "Score for the criterion (0 to 10)"
      }
    },
    "additionalProperties": false
  }
}

